/**
 * Detect and replace the deprecated `ktlint-disable` and `ktlint-enable` directives with `@Suppress` annotations.
 *
 * The ktlint-disable directive with rules in the EOL comment `// ktlint-disable some-rule-id` is replaced with the
 * `@Suppress` annotation which is placed on the associated declaration:
 * ```
 * // Before
 * val foo = "foo" // ktlint-disable some-rule-id
 *
 * // After
 * @Suppress("ktlint:standard:some-rule-id")
 * val foo = "foo"
 * ```
 *
 * The block `ktlint-disable` and `ktlint-enable` directives:
 * ```
 * /* ktlint-disable some-rule-id */
 * val foo = "foo"
 * /* ktlint-enable some-rule-id */
 * ```
 * are replaced with a `@Suppress` annotation as long as only a single construct (statement, declaration, expression)
 * is enclosed between the directives:
 * ```
 * @Suppress("ktlint:standard:some-rule-id")
 * val foo = "foo"
 * ```
 */
@SinceKtlint("0.50", EXPERIMENTAL)
public class KtlintSuppressionRule :
    StandardRule(
        id = "ktlint-suppression",
        usesEditorConfigProperties =
            setOf(
                INDENT_SIZE_PROPERTY,
                INDENT_STYLE_PROPERTY,
            ),
    ),
    Rule.Experimental {
    private val ktlintSuppressionRuleId = RuleId("standard:$KTLINT_SUPPRESSION_RULE_ID")

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        node
            .takeIf { it.elementType == EOL_COMMENT }
            ?.takeIf { it.isKtlintDisableDirective() }
            ?.let { visitEolComment(it, autoCorrect, emit) }

        node
            .takeIf { it.elementType == BLOCK_COMMENT }
            ?.takeIf { it.isKtlintDisableOrEnableDirective() }
            ?.let { visitBlockComment(it, autoCorrect, emit) }
    }

    private fun ASTNode.isKtlintDisableDirective() =
        text
            .removePrefix("//")
            .trim()
            .startsWith(KTLINT_DISABLE)

    private fun ASTNode.isKtlintDisableOrEnableDirective() =
        text
            .removePrefix("/*")
            .removeSuffix("*/")
            .trim()
            .let { it.startsWith(KTLINT_DISABLE) || it.startsWith(KTLINT_ENABLE) }

    private fun visitEolComment(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val ktlintDirectiveRuleIds = node.getKtlintDirectiveRuleIds()
        val targetNode = node.findTargetNodeForSuppressAnnotation()
        if (targetNode == null) {
            // The EOL comment is not part of a construct that can be annotated with @Suppress
            emit(
                node.startOffset,
                "Directive 'ktlint-disable' in EOL comment is deprecated. The matching Suppress annotation can not be added as it is not " +
                    "possible to determine to which statement/declaration the annotation should be added.",
                false,
            )
            return
        }

        val suppressionAnnotations = ktlintDirectiveRuleIds.toSuppressAnnotations()
        emit(
            node.startOffset,
            "Directive 'ktlint-disable' in EOL comment is deprecated. Replace with @Suppress annotation",
            true,
        )
        if (autoCorrect) {
            targetNode.addSuppressAnnotation(suppressionAnnotations)
            node.removeWithPrecedingWhitespace()
        }
    }

    private fun visitBlockComment(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val directiveText =
            node
                .text
                .removePrefix("/*")
                .removeSuffix("*/")
                .trim()
        when {
            directiveText.startsWith(KTLINT_DISABLE) -> {
                visitBlockCommentDisableDirective(node, autoCorrect, emit)
            }

            directiveText.startsWith(KTLINT_ENABLE) -> {
                // The ktlint-enable block comment will be removed when removing the ktlint-disable block comment
                emit(
                    node.startOffset,
                    "Directive 'ktlint-enable' in block comment is deprecated. Remove, as matching 'ktlint-disable' directive has been " +
                        "replaced with @Suppress annotation.",
                    true,
                )
                if (autoCorrect) {
                    node.removeWithSurroundingWhitespace()
                }
            }
        }
    }

    private fun visitBlockCommentDisableDirective(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val ktlintDirectiveRuleIds = node.getKtlintDirectiveRuleIds()
        val matchingEnableDirective = node.findMatchingEnableDirective(ktlintDirectiveRuleIds)

        if (matchingEnableDirective == null) {
            // No matching enable directive found. The disable directive applies until end of file. In case the directive is placed at the
            // start of the file, it can be transformed to a file-level annotation. Otherwise, the autocorrect can not be performed.
            val targetNode = node.findTargetNodeForFileLevelSuppression()
            if (targetNode == null) {
                emit(
                    node.startOffset,
                    "Directive 'ktlint-disable' in block comment is deprecated. The matching Suppress annotation can not be added as it " +
                        "is not possible to determine to which statement/declaration the annotation should be added.",
                    false,
                )
                return
            }
            val suppressionAnnotations = ktlintDirectiveRuleIds.toSuppressAnnotations()
            emit(
                node.startOffset,
                "Directive 'ktlint-disable' in block comment is deprecated. Replace with @file:Suppress annotation",
                true,
            )
            if (autoCorrect) {
                targetNode.addFileLevelSuppressAnnotation(suppressionAnnotations)
                node.removeWithSurroundingWhitespace()
            }
            return
        }

        val targetNode = node.findSingleCodeSiblingBefore(matchingEnableDirective)
        if (targetNode == null) {
            emit(
                node.startOffset,
                "Directive 'ktlint-disable' and 'ktlint-enable' in block comment are deprecated. The matching Suppress annotation can not " +
                    "be added as no single statement/declaration was found between the directives.",
                false,
            )
            return
        }

        val suppressionAnnotations = ktlintDirectiveRuleIds.toSuppressAnnotations()
        emit(
            node.startOffset,
            "Directive 'ktlint-disable' in block comment is deprecated. Replace with @Suppress annotation",
            true,
        )
        if (autoCorrect) {
            targetNode.addSuppressAnnotation(suppressionAnnotations)
            node.removeWithSurroundingWhitespace()
            matchingEnableDirective.removeWithSurroundingWhitespace()
        }
    }

    private fun ASTNode.getKtlintDirectiveRuleIds(): List<String> =
        text
            .removePrefix("//")
            .removePrefix("/*")
            .removeSuffix("*/")
            .trim()
            .removePrefix(KTLINT_DISABLE)
            .removePrefix(KTLINT_ENABLE)
            .trim()
            .split("\\s+".toRegex())
            .filter { it.isNotBlank() }
            .map { ruleId ->
                // Prefix unqualified rule id with standard rule set id
                if (ruleId.contains(":")) {
                    ruleId
                } else {
                    "standard:$ruleId"
                }
            }

    private fun List<String>.toSuppressAnnotations(): List<String> =
        if (isEmpty()) {
            // No specific rules defined, suppress all ktlint rules
            listOf("\"ktlint\"")
        } else {
            map { "\"ktlint:$it\"" }
        }

    private fun ASTNode.findTargetNodeForSuppressAnnotation(): ASTNode? {
        val targetNode =
            // EOL comment after a leaf element should suppress the first non-whitespace parent of the leaf element
            prevSibling { !it.isWhiteSpace() && !it.isPartOfComment() }
                // EOL comment on its own line or after a comment should suppress the next sibling
                ?: nextCodeSibling()
        return when {
            targetNode == null -> null
            targetNode.psi is KtPackageDirective -> null
            targetNode.psi is KtImportList -> null
            targetNode.psi is KtImportDirective -> null
            targetNode.psi is KtScript -> null
            targetNode.psi is KtFileAnnotationList -> null
            else -> targetNode
        }
    }

    private fun ASTNode.findTargetNodeForFileLevelSuppression(): ASTNode? {
        // Only the ktlint-disable block comment at top of the file (before the package directive) can be converted to a file level
        // suppression
        val firstCodeSibling = treeParent.children().firstOrNull { !it.isWhiteSpace() && !it.isPartOfComment() }
        return when {
            firstCodeSibling == null -> null
            firstCodeSibling.psi is KtPackageDirective -> {
                // Check if there is another code element between this node and the package directive
                val nextCodeSibling = nextCodeSibling()
                if (nextCodeSibling == null || nextCodeSibling == firstCodeSibling) {
                    // No code found between comment and package directive
                    treeParent
                } else {
                    // Code found between comment and package directive
                    null
                }
            }
            else -> null
        }
    }

    private fun ASTNode.findMatchingEnableDirective(ktlintDirectiveRuleIds: List<String>): ASTNode? =
        siblings(forward = true)
            .firstOrNull { sibling ->
                sibling.elementType == BLOCK_COMMENT &&
                    sibling.isKtlintEnableDirective() &&
                    sibling.getKtlintDirectiveRuleIds() == ktlintDirectiveRuleIds
            }

    private fun ASTNode.isKtlintEnableDirective() =
        text
            .removePrefix("/*")
            .removeSuffix("*/")
            .trim()
            .startsWith(KTLINT_ENABLE)

    private fun ASTNode.findSingleCodeSiblingBefore(matchingEnableDirective: ASTNode): ASTNode? {
        val codeSiblings =
            siblings(forward = true)
                .takeWhile { it != matchingEnableDirective }
                .filter { !it.isWhiteSpace() && !it.isPartOfComment() }
                .toList()
        return codeSiblings.singleOrNull()
    }

    private fun ASTNode.addSuppressAnnotation(suppressionAnnotations: List<String>) {
        when (val psi = psi) {
            is KtDeclaration -> addSuppressAnnotationToDeclaration(suppressionAnnotations)

            is KtAnnotatedExpression -> {
                // Add suppression to the existing annotation entries
                addSuppressAnnotationToAnnotationEntry(suppressionAnnotations)
            }

            is KtCallExpression,
            is KtLambdaExpression,
            -> {
                // Wrap the expression with @Suppress annotation
                wrapExpressionWithSuppressAnnotation(suppressionAnnotations)
            }

            else -> {
                // Try to find a parent that can be annotated
                val parent = psi.parent
                when {
                    parent is KtDeclaration -> treeParent.addSuppressAnnotationToDeclaration(suppressionAnnotations)
                    parent is KtAnnotatedExpression ->
                        treeParent.addSuppressAnnotationToAnnotationEntry(
                            suppressionAnnotations,
                        )
                    else -> wrapExpressionWithSuppressAnnotation(suppressionAnnotations)
                }
            }
        }
    }

    private fun ASTNode.addSuppressAnnotationToDeclaration(suppressionAnnotations: List<String>) {
        val annotationText = "@Suppress(${suppressionAnnotations.joinToString(", ")})"
        val indent = indent(false)
        val modifierList = psi.getChildOfType<KtDeclarationModifierList>()
        if (modifierList != null) {
            // Check if @Suppress annotation already exists
            val existingSuppressEntry =
                modifierList
                    .annotationEntries
                    .firstOrNull { it.shortName?.asString() in listOf("Suppress", "SuppressWarnings") }
            if (existingSuppressEntry != null) {
                // Merge with existing @Suppress annotation
                existingSuppressEntry.mergeSuppressAnnotation(suppressionAnnotations)
            } else {
                // Add new annotation before modifier list
                val modifierListNode = modifierList.node
                modifierListNode.addLeafElementAt(annotationText, 0)
                modifierListNode.addLeafElementAt("\n$indent", annotationText.length)
            }
        } else {
            // No modifiers exist, create a new modifier list with the annotation
            val annotationNode = LeafPsiElement(ANNOTATION_ENTRY, annotationText)
            val whitespaceNode = PsiWhiteSpaceImpl("\n$indent")
            this.addChild(annotationNode, firstChildNode)
            this.addChild(whitespaceNode, firstChildNode.nextSibling)
        }
    }

    private fun KtAnnotationEntry.mergeSuppressAnnotation(suppressionAnnotations: List<String>) {
        val existingArguments =
            valueArguments
                .mapNotNull { it.getArgumentExpression()?.text }
        val newArguments = suppressionAnnotations.filter { it !in existingArguments }
        if (newArguments.isEmpty()) return

        val allArguments = existingArguments + newArguments
        val newAnnotationText = "@Suppress(${allArguments.joinToString(", ")})"

        val parent = node.treeParent
        val newAnnotationNode = LeafPsiElement(ANNOTATION_ENTRY, newAnnotationText)
        parent.replaceChild(node, newAnnotationNode)
    }

    private fun ASTNode.addLeafElementAt(
        text: String,
        position: Int,
    ) {
        val textBefore = this.text.substring(0, position)
        val textAfter = this.text.substring(position)
        (this.firstChildNode as LeafPsiElement).rawReplaceWithText(textBefore + text + textAfter)
    }

    private fun ASTNode.addSuppressAnnotationToAnnotationEntry(suppressionAnnotations: List<String>) {
        val annotatedExpression = psi as? KtAnnotatedExpression ?: return
        val existingSuppressEntry =
            annotatedExpression
                .annotationEntries
                .firstOrNull { it.shortName?.asString() in listOf("Suppress", "SuppressWarnings") }
        if (existingSuppressEntry != null) {
            existingSuppressEntry.mergeSuppressAnnotation(suppressionAnnotations)
        } else {
            // Add new @Suppress annotation before the first existing annotation
            val annotationText = "@Suppress(${suppressionAnnotations.joinToString(", ")})\n${indent(false)}"
            val firstAnnotation = annotatedExpression.annotationEntries.first()
            val newAnnotationNode = LeafPsiElement(ANNOTATION_ENTRY, annotationText)
            this.addChild(newAnnotationNode, firstAnnotation.node)
        }
    }

    private fun ASTNode.wrapExpressionWithSuppressAnnotation(suppressionAnnotations: List<String>) {
        val annotationText = "@Suppress(${suppressionAnnotations.joinToString(", ")})"
        val indent = indent(false)
        val annotationNode = LeafPsiElement(ANNOTATION_ENTRY, annotationText)
        val whitespaceNode = PsiWhiteSpaceImpl("\n$indent")
        treeParent.addChild(annotationNode, this)
        treeParent.addChild(whitespaceNode, this)
    }

    private fun ASTNode.addFileLevelSuppressAnnotation(suppressionAnnotations: List<String>) {
        val annotationText = "@file:Suppress(${suppressionAnnotations.joinToString(", ")})\n\n"

        // Find or create file annotation list
        val existingFileAnnotationList = children().firstOrNull { it.elementType == FILE_ANNOTATION_LIST }
        if (existingFileAnnotationList != null) {
            // Add to existing file annotation list or merge with existing @Suppress
            val existingSuppressEntry =
                existingFileAnnotationList
                    .children()
                    .filter { it.elementType == ANNOTATION_ENTRY }
                    .mapNotNull { it.psi as? KtAnnotationEntry }
                    .firstOrNull { it.shortName?.asString() in listOf("Suppress", "SuppressWarnings") }
            if (existingSuppressEntry != null) {
                existingSuppressEntry.mergeSuppressAnnotation(suppressionAnnotations)
            } else {
                // Add new annotation after existing file annotations
                val annotationNode = LeafPsiElement(ANNOTATION_ENTRY, annotationText)
                existingFileAnnotationList.addChild(annotationNode, existingFileAnnotationList.lastChildNode?.nextSibling)
            }
        } else {
            // Create new file annotation
            val annotationNode = LeafPsiElement(ANNOTATION_ENTRY, annotationText)
            this.addChild(annotationNode, firstChildNode)
        }
    }

    private fun ASTNode.removeWithPrecedingWhitespace() {
        val prevWhitespace = prevLeaf()?.takeIf { it.isWhiteSpace() }
        treeParent.removeChild(this)
        prevWhitespace?.let { whitespace ->
            if (whitespace.textContains('\n')) {
                // Keep the newline, just remove the content after it
                val text = whitespace.text
                val lastNewlineIndex = text.lastIndexOf('\n')
                val newText = text.substring(0, lastNewlineIndex + 1)
                if (newText.isEmpty()) {
                    whitespace.treeParent?.removeChild(whitespace)
                } else {
                    (whitespace as LeafPsiElement).rawReplaceWithText(newText)
                }
            } else {
                whitespace.treeParent?.removeChild(whitespace)
            }
        }
    }

    private fun ASTNode.removeWithSurroundingWhitespace() {
        val prevWhitespace = prevLeaf()?.takeIf { it.isWhiteSpace() }
        val nextWhitespace = nextLeaf()?.takeIf { it.isWhiteSpace() }

        // Remove the comment node first
        treeParent.removeChild(this)

        // Handle surrounding whitespace
        if (prevWhitespace != null && nextWhitespace != null) {
            // Merge whitespaces if both exist
            val prevHasNewline = prevWhitespace.textContains('\n')
            val nextHasNewline = nextWhitespace.textContains('\n')
            if (prevHasNewline && nextHasNewline) {
                // Keep only the newline from prev
                nextWhitespace.treeParent?.removeChild(nextWhitespace)
            } else if (prevHasNewline) {
                nextWhitespace.treeParent?.removeChild(nextWhitespace)
            } else {
                prevWhitespace.treeParent?.removeChild(prevWhitespace)
            }
        } else if (prevWhitespace != null && !prevWhitespace.textContains('\n')) {
            prevWhitespace.treeParent?.removeChild(prevWhitespace)
        } else if (nextWhitespace != null && !nextWhitespace.textContains('\n')) {
            nextWhitespace.treeParent?.removeChild(nextWhitespace)
        }
    }

    private companion object {
        const val KTLINT_DISABLE = "ktlint-disable"
        const val KTLINT_ENABLE = "ktlint-enable"
    }
}

public const val KTLINT_SUPPRESSION_RULE_ID: String = "ktlint-suppression"
public val KTLINT_SUPPRESSION_RULE_RULE_ID: RuleId = RuleId("standard:$KTLINT_SUPPRESSION_RULE_ID")
"}

