        if (existingFileAnnotationList != null) {
            // Add to existing file annotation list or merge with existing @Suppress
            val existingSuppressEntry =
                existingFileAnnotationList
                    .children()
                    .filter { it.elementType == ANNOTATION_ENTRY }
                    .mapNotNull { it.psi as? KtAnnotationEntry }
                    .firstOrNull { it.shortName?.asString() in listOf("Suppress", "SuppressWarnings") }
            if (existingSuppressEntry != null) {
                existingSuppressEntry.mergeSuppressAnnotation(suppressionAnnotations)
            } else {
                // Add new annotation after existing file annotations
                val annotationNode = LeafPsiElement(ANNOTATION_ENTRY, annotationText)
                existingFileAnnotationList.addChild(annotationNode, existingFileAnnotationList.lastChildNode?.nextSibling)
            }
        } else {
            // Create new file annotation
            val annotationNode = LeafPsiElement(ANNOTATION_ENTRY, annotationText)
            this.addChild(annotationNode, firstChildNode)
        }
    }

    private fun ASTNode.removeWithPrecedingWhitespace() {
        val prevWhitespace = prevLeaf()?.takeIf { it.isWhiteSpace() }
        treeParent.removeChild(this)
        prevWhitespace?.let { whitespace ->
            if (whitespace.textContains('\n')) {
                // Keep the newline, just remove the content after it
                val text = whitespace.text
                val lastNewlineIndex = text.lastIndexOf('\n')
                val newText = text.substring(0, lastNewlineIndex + 1)
                if (newText.isEmpty()) {
                    whitespace.treeParent?.removeChild(whitespace)
                } else {
                    (whitespace as LeafPsiElement).rawReplaceWithText(newText)
                }
            } else {
                whitespace.treeParent?.removeChild(whitespace)
            }
        }
    }

    private fun ASTNode.removeWithSurroundingWhitespace() {
        val prevWhitespace = prevLeaf()?.takeIf { it.isWhiteSpace() }
        val nextWhitespace = nextLeaf()?.takeIf { it.isWhiteSpace() }

        // Remove the comment node first
        treeParent.removeChild(this)

        // Handle surrounding whitespace
        if (prevWhitespace != null && nextWhitespace != null) {
            // Merge whitespaces if both exist
            val prevHasNewline = prevWhitespace.textContains('\n')
            val nextHasNewline = nextWhitespace.textContains('\n')
            if (prevHasNewline && nextHasNewline) {
                // Keep only the newline from prev
                nextWhitespace.treeParent?.removeChild(nextWhitespace)
            } else if (prevHasNewline) {
                nextWhitespace.treeParent?.removeChild(nextWhitespace)
            } else {
                prevWhitespace.treeParent?.removeChild(prevWhitespace)
            }
        } else if (prevWhitespace != null && !prevWhitespace.textContains('\n')) {
            prevWhitespace.treeParent?.removeChild(prevWhitespace)
        } else if (nextWhitespace != null && !nextWhitespace.textContains('\n')) {
            nextWhitespace.treeParent?.removeChild(nextWhitespace)
        }
    }

    private companion object {
        const val KTLINT_DISABLE = "ktlint-disable"
        const val KTLINT_ENABLE = "ktlint-enable"
    }
}

